let history = flow.get("sensor_table") || [];

let hours = flow.get('filter_time') || 1;
let cutoff = Date.now() - hours * 3600000;

let filtered = history.filter(r => r.time > cutoff);

filtered.forEach(r => {
    node.send({
        topic: r.sensor,
        payload: r.value
    });
});

return null;
